    // For S == 256 each lane therefore carries two vectors, covering all four
    // bf16 values assigned to it in the final partition output.
    for (uint i = 0; i < HQ / HK / 4; i++) {
        uint m_token_id = HQ / HK / 4 * warp_id + i;
        if (m_token_id < HQ / HK) {
            const uint shared_vec = (m_token_id ^ (lane_id / 2)) * 2 + (lane_id & 1);
            float32x2 out_v[S / 128];
            #pragma unroll
            for (uint d = 0; d < S / 128; ++d) {
                bfloat16x2 tmp = ((bfloat16x2*)(share_buf.get_out_buf(0) + m_token_id * S))[shared_vec + d * 64];
                out_v[d][0] = tmp[0];
                out_v[d][1] = tmp[1];
                out_v[d] = sums[4 * i + 0] * __expf(maxs[4 * i + 0] - real_max[i]) * out_v[d];
