                #pragma unroll
                for (uint d = 0; d < S / 128; ++d) {
                    auto tmp = ((bfloat16x2*)(share_buf.get_out_buf(w) + m_token_id * S))[shared_vec + d * 64];
                    float32x2 next_v;
                    next_v[0] = tmp[0];
                    next_v[1] = tmp[1];
                    out_v[d] += warp_scale * next_v;
