            #pragma unroll
            for (uint d = 0; d < S / 128; ++d) {
                out_v[d] = out_v[d] * inv_sum_scale;
                bfloat16x2 tmp_out;
                tmp_out[0] = std::bit_cast<__bf16>((ushort)(std::bit_cast<uint>(out_v[d][0]) >> 16));
                tmp_out[1] = std::bit_cast<__bf16>((ushort)(std::bit_cast<uint>(out_v[d][1]) >> 16));
                ((bfloat16x2*)(out_seg + m_token_id * gridDim.z * S))[lane_id + d * 64] = tmp_out;
            }
            max_out[m_token_id * gridDim.z] = real_max[i];
            sum_out[m_token_id * gridDim.z] = real_sum[i];
        }
    }
}

__global__ void __launch_bounds__(NUM_THREADS, 2) pa_reduce(
            uint* kv_indptr,        // [B + 1]
            __bf16* out_seg,        // [B, HQ, PART, S]
            float* max_out,         // [B, HQ, PART, 1]
            float* sum_out,         // [B, HQ, PART, 1]
            __bf16* out,            // [B, HQ, S]
            uint max_part
            ) {
    // wg: B, HQ
    uint b = blockIdx.x;
    uint hq = blockIdx.y;
    uint lane_id = threadIdx.x % 64;
    uint warp_id = threadIdx.x / 64;
    out += b * HQ * S + hq * S;
    out_seg += b * HQ * max_part * S + hq * max_part * S;
    max_out += b * HQ * max_part * 1 + hq * max_part * 1;
    sum_out += b * HQ * max_part * 1 + hq * max_part * 1;
    uint kv_len = kv_indptr[b + 1] - kv_indptr[b];
    uint part_num = (kv_len + KV_PART_SIZE - 1) / KV_PART_SIZE;
    float real_max = -FLT_MAX;
    for (uint i = lane_id; i < part_num; i += 64) {
        real_max = fmaxf(real_max, max_out[i]);
    }
    for (uint mask = 64 / 2; mask >= 1; mask /= 2) {
        real_max = fmaxf(real_max, __shfl_xor(real_max, mask));
    }

    // 64 lanes x bfloat16x2 covers 128 elements.  Retain both halves of a
    // 256-wide head throughout the partition reduction.
    float32x2 cur_val[S / 128] = {0};
    float warp_sum = 0;
    for (uint i = warp_id; i < part_num; i += 4) {
        auto cur_max = max_out[i];
        auto cur_out_seg = out_seg + i * S;
        const float part_scale = sum_out[i] * __expf(cur_max - real_max);
        #pragma unroll
        for (uint d = 0; d < S / 128; ++d) {
            auto cur_val_low = ((bfloat16x2*)cur_out_seg)[lane_id + d * 64];
            float32x2 tmp_val;
            tmp_val[0] = cur_val_low[0];
            tmp_val[1] = cur_val_low[1];
            cur_val[d] += tmp_val * part_scale;
        }
        warp_sum += part_scale;
    }

    __shared__ float out_lds[4 * S];
    __shared__ float sum_lds[4];
    if (lane_id == 0) {
        sum_lds[warp_id] = warp_sum;
    }
    if (warp_id != 0) {
        #pragma unroll
        for (uint d = 0; d < S / 128; ++d) {
            *(float32x2*)(&out_lds[warp_id * S + d * 128 + lane_id * 2]) = cur_val[d];
        }
    }
    __syncthreads();
    if (warp_id == 0) {
        warp_sum += sum_lds[1] + sum_lds[2] + sum_lds[3];
        for (int i = 1; i < 4; i++) {
            #pragma unroll
            for (uint d = 0; d < S / 128; ++d) {
                cur_val[d] += *(float32x2*)(&out_lds[i * S + d * 128 + lane_id * 2]);
            }
        }
        const float inv_sum_scale = 1.f / (warp_sum + 1e-6f);
        #pragma unroll
        for (uint d = 0; d < S / 128; ++d) {
            cur_val[d] *= inv_sum_scale;
            bfloat16x2 tmp_val;
            tmp_val[0] = cur_val[d][0];
            tmp_val[1] = cur_val[d][1];
            ((bfloat16x2*)out)[lane_id + d * 64] = tmp_val;
        }
    }
}

